import { AcademicModule } from "@academic/academic.module";
import { Module } from "@nestjs/common";
import { ConfigModule } from "@nestjs/config";
import { SharedModule } from "@shared/shared.module";

@Module({
  imports: [
    ConfigModule.forRoot(),
    SharedModule,
    AcademicModule,
  ],
})
export class AppModule {}

import { StudentService } from "@academic/students/application/services/student.service";
import { STUDENT_REPOSITORY } from "@academic/students/domain/repositories/student-repository.interface";
import { StudentsController } from "@academic/students/infra/controllers/students.controller";
import { DrizzleStudentRepository } from "@academic/students/infra/repositories/drizzle-student.repository";
import { Module } from "@nestjs/common";
import { SharedModule } from "@shared/shared.module";

@Module({
  imports: [SharedModule],
  controllers: [StudentsController],
  providers: [
    StudentService,
    DrizzleStudentRepository,
    {
      provide: STUDENT_REPOSITORY,
      useExisting: DrizzleStudentRepository,
    },
  ],
})
export class StudentsModule {}

import { Student } from "@academic/students/domain/models/student.entity";
import type { StudentRepository } from "@academic/students/domain/repositories/student-repository.interface";
import { studentsSchema } from "@academic/students/infra/database/schemas/student.schema";
import { Injectable } from "@nestjs/common";
import { DrizzleService } from "@shared/infra/database/drizzle.service";
import { eq } from "drizzle-orm";

@Injectable()
export class DrizzleStudentRepository implements StudentRepository {
  constructor(private readonly drizzleService: DrizzleService) {}

  async create(student: Student): Promise<void> {
    await this.drizzleService.db.insert(studentsSchema).values({
      name: student.name,
      email: student.email,
      document: student.document,
      registration: student.registration,
      createdAt: new Date(),
      updatedAt: new Date(),
    });
  }

  async update(student: Student): Promise<void> {
    await this.drizzleService.db
      .update(studentsSchema)
      .set({
        name: student.name,
        email: student.email,
        document: student.document,
        registration: student.registration,
        updatedAt: new Date(),
      })
      .where(eq(studentsSchema.id, student.id!));
  }

  async delete(id: string): Promise<void> {
    await this.drizzleService.db
      .delete(studentsSchema)
      .where(eq(studentsSchema.id, id));
  }

  async findById(id: string): Promise<Student | null> {
    const result = await this.drizzleService.db
      .select()
      .from(studentsSchema)
      .where(eq(studentsSchema.id, id))
      .limit(1);

    return Student.restore(result[0]);
  }

  async findByEmail(email: string): Promise<Student | null> {
    const result = await this.drizzleService.db
      .select()
      .from(studentsSchema)
      .where(eq(studentsSchema.email, email.toLowerCase()))
      .limit(1);

    return Student.restore(result[0]);
  }

  async findAll(): Promise<Student[]> {
    const rows = await this.drizzleService.db.select().from(studentsSchema);
    return rows.map((row) => Student.restore(row)!);
  }
}
